INSERT INTO `genres` (id, name, kana, overview, code, created_at, updated_at) VALUES (1, 'アクション', 'アクション', 'アクションゲームとは、プレイヤーが主人公を操作し、敵を倒したり、障害物を避けたり、ステージをクリアしていくゲームのジャンルのことです。主にアクションゲームは、キャラクターや武器を操作して進む横スクロール型や、3D空間を舞台にした3Dアクションゲームなどがあります。また、ジャンプやダッシュ、攻撃などのアクション操作に加え、ジャンプアクションやシューティング、格闘アクションなどのサブジャンルも存在します。アクションゲームは、手軽に遊べるものから難易度の高いものまで多種多様で、幅広い層のプレイヤーに楽しまれています。', 'ACT', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `genres` (id, name, kana, overview, code, created_at, updated_at) VALUES (2, 'アドベンチャー', 'アドベンチャー', 'アドベンチャーゲームは、ストーリーやキャラクターの成長を重視したゲームのジャンルです。主にテキストやイラストを使い、プレイヤーが物語の展開や進行を決めていきます。キャラクターたちとの会話や謎解きなど、ストーリーを進めるためには様々なアクションが必要になります。また、アドベンチャーゲームにはサウンドノベルと呼ばれる音声演出に力を入れたタイプのものもあります。代表的なアドベンチャーゲームには、「ファミコン探偵倶楽部」や「シナリオテキストアドベンチャー」などがあります。', 'ADV', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `genres` (id, name, kana, overview, code, created_at, updated_at) VALUES (3, 'ロールプレイング', 'ロールプレイング', 'ロールプレイングゲーム（RPG）は、主にキャラクターの成長やストーリーの進行に重点を置いたテレビゲームのジャンルです。プレイヤーは、主人公やその仲間たちを操作して、モンスターや敵キャラクターとの戦闘を繰り広げながら、ストーリーを進めていくことが目的となります。プレイヤーが選択した選択肢によって、ストーリーの展開やエンディングが変化することがあります。RPGは、ダンジョン探索やアイテム集めなどの要素も含んでおり、広大な世界観や複雑なシステムが特徴的です。また、キャラクターの成長によって能力が向上するシステム（レベルアップ）や、ダイスなどを使ったランダム性を取り入れた戦闘システムもあります。代表的なRPGには、「ファイナルファンタジー」シリーズ、「ドラゴンクエスト」シリーズ、「ゼルダの伝説」シリーズなどがあります。', 'RPG', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `genres` (id, name, kana, overview, code, created_at, updated_at) VALUES (4, 'シミュレーション', 'シミュレーション', '「シミュレーションゲーム」とは、現実世界のある種のシステムや状況を模擬してプレイヤーに体験させるゲームジャンルのひとつです。例えば、都市や国家の経営、戦争や戦闘システムの再現、交通機関の運営、農場や牧場の経営、人生シミュレーションなど、多様な種類があります。プレイヤーは、現実に起こりうる様々な状況に直面し、自らの判断や選択によって、その状況をコントロールしながらゲームを進めていきます。シミュレーションゲームは、リアリティを重視することで、現実の状況に即したシステムやルールを取り入れ、プレイヤーにより深い没入感を提供します。', 'SLG', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `genres` (id, name, kana, overview, code, created_at, updated_at) VALUES (5, 'シューティング', 'シューティング', '「シューティングゲーム」とは、プレイヤーが主人公のキャラクターを操作して敵キャラクターを撃破することを目的としたテレビゲームのジャンルのひとつです。プレイヤーは、敵からの攻撃を回避しつつ、自機の攻撃で敵を撃破していくことが求められます。代表的な作品には、「スペースインベーダー」や「グラディウス」、「R-TYPE」などがあります。また、近年では3Dグラフィックスを採用した作品も多く登場しており、リアルな戦闘シーンを楽しめるようになっています。シューティングゲームは、反射神経や戦略性を駆使して高得点を目指すことができる、エキサイティングなジャンルのひとつです。', 'STG', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `genres` (id, name, kana, overview, code, created_at, updated_at) VALUES (6, 'テーブル', 'テーブル', '「テーブルゲーム」とは、テレビゲームのジャンルのひとつで、卓上遊戯とも呼ばれ、ボードゲームやカードゲーム、麻雀など、テーブルの上で行われる様々な種類のゲームを指します。一部のテーブルゲームはコンピューターゲームとしても展開されていますが、その多くはアナログゲームとして、紙やダイス、トークン、カードなどを使って遊ばれます。プレイヤー同士の交渉や、戦略的な判断力、運を要するものもあり、社交性やコミュニケーション能力を養うことができることも魅力のひとつです。テーブルゲームは、家族や友人との時間を楽しむために広くプレイされているほか、プロフェッショナルプレイヤーがいる競技化されたゲームも存在します。', 'TBL', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `genres` (id, name, kana, overview, code, created_at, updated_at) VALUES (7, 'スポーツ', 'スポーツ', 'スポーツゲームとは、様々なスポーツ競技を題材にしたテレビゲームのジャンルです。実在するスポーツチームや選手、スタジアムなどが再現され、プレイヤーは自分が好きなチームや選手を選んで試合を行うことができます。代表的なスポーツゲームには、野球、サッカー、バスケットボール、フットボール、テニス、ゴルフなどがあります。プレイヤーはリアルなルールや戦術を再現されたゲームの中で試合を行い、勝利を目指します。多くのスポーツゲームでは、オンライン対戦モードもあり、他のプレイヤーと対戦することができます。', 'SPT', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `genres` (id, name, kana, overview, code, created_at, updated_at) VALUES (8, '恋愛', 'レンアイ', '「恋愛ゲーム」とは、プレイヤーが主人公となって、仮想の異性キャラクターとの恋愛を描いたゲームのことを指します。ストーリーを進めることで、キャラクターたちとの会話やデート、選択肢を選んでストーリーを分岐させたりすることができます。一部のゲームでは、主人公とキャラクターたちとの関係性を深めるために、特定の条件を満たす必要があることもあります。恋愛ゲームは、女性向け・男性向け・同性愛向けなど、さまざまなターゲット層があり、人気作品は多くのファンを獲得しています。', 'LOVE', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `genres` (id, name, kana, overview, code, created_at, updated_at) VALUES (9, '格闘', 'カクトウ', '格闘ゲームは、対戦型のアクションゲームの一種で、プレイヤーが選んだキャラクターを操作して、対戦相手を倒すことを目的とするゲームです。プレイヤーは、攻撃や防御、ジャンプ、回避などのアクションを駆使して相手を攻撃し、相手の体力をゼロにすることで勝利します。多くの格闘ゲームには、各キャラクターが持つ特定の必殺技やコンボ技などの特徴的な攻撃があり、プレイヤーはそれらを使いこなすことで勝利を目指します。格闘ゲームは、アーケードゲームや家庭用ゲーム機などで人気があり、世界的にも大きな競技大会が開かれるなど、競技性が高いゲームとして知られています。', 'FTG', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `genres` (id, name, kana, overview, code, created_at, updated_at) VALUES (10, 'レース', 'レース', 'レースゲームとは、車やバイクなどの乗り物を操作して競い合うテレビゲームのジャンルです。多くのレースゲームでは、プレイヤーは速度やコースの選択、ライバルとの接触回避や先回りなどを戦略的に判断しながら、レースの優勝を目指します。また、リアルなシミュレーションやアーケード的なアクション要素を取り入れたもの、カートゥーン的なキャラクターやアイテムを駆使するものなど、様々なバリエーションがあります。レースゲームは、リアルな車やバイクの走行感覚を再現することで、現実ではなかなかできないスピード感や競争の緊張感を味わうことができます。', 'RCE', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `genres` (id, name, kana, overview, code, created_at, updated_at) VALUES (11, 'パズル', 'パズル', 'テレビゲームのジャンルのひとつである「パズルゲーム」とは、主に頭脳を使うことで進めるゲームのことを指します。ゲーム内で与えられた問題を解決するため、プレイヤーはロジックや推論能力を使い、タイミングを計りながらパズルのピースを組み合わせたり、配置を変えたりします。簡単なものから、非常に難しいものまで様々な難易度のゲームがあります。代表的なパズルゲームには、テトリスやパネルでポン、ジグソーパズルなどがあります。また、近年ではスマートフォンアプリにも多数のパズルゲームがリリースされています。', 'PZL', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `genres` (id, name, kana, overview, code, created_at, updated_at) VALUES (12, '音楽ゲーム', 'オンガクゲーム', '音楽ゲームとは、プレイヤーが楽曲に合わせて操作をすることで、楽曲を演奏するゲームです。代表的な音楽ゲームには、音符を叩くリズムゲームや、音符をタップするタップアクションゲームなどがあります。プレイヤーは楽曲のリズムやメロディーに合わせて操作をすることで、高得点を獲得したり、難易度の高いステージをクリアすることが目的となります。音楽ゲームは、音楽に興味がある人や、リズム感を養いたい人にとっては楽しく、また、音楽を楽しむ新しい形態の1つとしても広く親しまれています。', 'MSC', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `genres` (id, name, kana, overview, code, created_at, updated_at) VALUES (13, 'その他', 'ソノタ', '他のジャンルに分類が難しいゲームを取り扱います。\r\n図鑑ゲームなどがこちらに該当します。\r\n適切な分類が見つかった場合は、適切なジャンルにゲームを移動します。', 'other', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);